// Unwrap GitHub webhook payload. n8n may place it under `body`.
// Skip irrelevant events, drafts, and PRs explicitly labelled to avoid AI review.
const root = $input.first().json;
const evt = root.body ?? root;
const allowed = ['opened', 'synchronize', 'reopened', 'ready_for_review'];

if (!evt.pull_request || !allowed.includes(evt.action)) return [];
if (evt.pull_request.draft) return [];

const labels = (evt.pull_request.labels || []).map(l => String(l.name || '').toLowerCase());
const skipLabels = new Set(['no-ai-review', 'skip-ai-review', 'ai-review-skip']);
if (labels.some(l => skipLabels.has(l))) return [];

return [{ json: evt }];

// Combine PR metadata with diff text. Do not silently truncate.
const evt  = $('Filter PR Events').first().json;
const pr   = evt.pull_request;
const repo = evt.repository;

let diff = $input.first().json.data;
if (diff === undefined) diff = $input.first().json.body ?? '';
if (typeof diff !== 'string') diff = JSON.stringify(diff);

const MAX_DIFF_CHARS = 60000;
const base = {
  owner: repo.owner.login,
  repo: repo.name,
  number: pr.number,
  commit_id: pr.head.sha,
  html_url: pr.html_url,
  pr_title: pr.title,
  head_ref: pr.head.ref,
  base_ref: pr.base.ref,
  diff_chars: diff.length
};

if (!diff || diff.trim().length === 0) {
  throw new Error('Empty diff for PR #' + pr.number);
}

if (diff.length > MAX_DIFF_CHARS) {
  return [{ json: {
    ...base,
    skipped: true,
    skip_reason: `Diff too large for safe automated review: ${diff.length} chars. Split the PR or run file-by-file review.`,
    code: '',
    language: 'auto-detect',
    context: `Unified diff for PR #${pr.number} "${pr.title}" (${pr.head.ref} -> ${pr.base.ref}). Diff omitted because it exceeds ${MAX_DIFF_CHARS} chars.`
  }}];
}

return [{ json: {
  ...base,
  skipped: false,
  code: diff,
  language: 'auto-detect',
  context: `Unified diff for PR #${pr.number} "${pr.title}" (${pr.head.ref} -> ${pr.base.ref}).`
}}];

