const data = $('Parse Input').first().json;
return JSON.stringify({
  language: data.language || 'auto-detect',
  context: (data.context && data.context.length) ? data.context : '(none provided)',
  code: data.code || ''
}, null, 2);

const raw = ($('Parse Input').first().json.code || '');
const code = raw
  .split('\n')
  .filter(l => l.startsWith('+') && !l.startsWith('+++'))
  .map(l => l.slice(1))
  .join('\n');

const lines = code.split('\n');
const loc = lines.length;
const nonEmpty = lines.filter(l => l.trim().length).length;
const approxFunctions = (code.match(/\bfunction\b|=>|\bdef\s+[A-Za-z_]/g) || []).length;

const loopRe = /\b(for|while)\b|\.forEach\s*\(|\.map\s*\(|\.filter\s*\(/;
let nestedLoops = 0;
const indentStack = [];
lines.forEach(line => {
  if (loopRe.test(line)) {
    const indent = line.length - line.trimStart().length;
    while (indentStack.length && indentStack[indentStack.length - 1] >= indent) indentStack.pop();
    indentStack.push(indent);
    if (indentStack.length >= 2) nestedLoops++;
  }
});

const scanInLoop = (predRe) => {
  let count = 0, inLoop = false, loopIndent = -1;
  lines.forEach(line => {
    const indent = line.length - line.trimStart().length;
    if (/\b(for|while)\b|\.forEach\s*\(/.test(line)) { inLoop = true; loopIndent = indent; }
    else if (inLoop && line.trim().length && indent <= loopIndent) { inLoop = false; }
    if (inLoop && predRe.test(line)) count++;
  });
  return count;
};

const sequentialAwaitsInLoops = scanInLoop(/\bawait\b/);
const possibleNPlusOneQueries = scanInLoop(/(query|find|select|fetch|save|insert|update|findOne|getBy)\s*\(/i);
const chainedArrayPasses = (code.match(/\.(map|filter|forEach|reduce)\s*\([^)]*\)\s*\.\s*(map|filter|forEach|reduce)\s*\(/g) || []).length;

return JSON.stringify({
  tool: 'ast_complexity_analysis',
  scope: 'added diff lines only',
  metrics: { totalAddedLines: loc, nonEmptyAddedLines: nonEmpty, approxFunctions },
  signals: { nestedLoops, sequentialAwaitsInLoops, possibleNPlusOneQueries, chainedArrayPasses },
  note: 'Heuristic line/regex analysis over added diff lines, not a full AST parse.'
}, null, 2);

const code = ($('Parse Input').first().json.code || '');
const lines = code.split('\n');
const findings = [];
const add = (i, severity, issue, snippet) =>
  findings.push({ line: i + 1, severity, issue, snippet: (snippet || '').trim().slice(0, 160) });

const checks = [
  { re: /\beval\s*\(/, sev: 'high', msg: 'Use of eval() enables arbitrary code execution' },
  { re: /new\s+Function\s*\(/, sev: 'high', msg: 'Dynamic code execution via new Function()' },
  { re: /child_process|\bexecSync\b|\bexec\s*\(|\bspawn\s*\(|os\.system|subprocess\.|Runtime\.getRuntime/, sev: 'high', msg: 'Shell/process execution' },
  { re: /(password|passwd|secret|api[_-]?key|apikey|token|access[_-]?key|private[_-]?key)\s*[:=]\s*['"][^'"]{6,}['"]/i, sev: 'high', msg: 'Possible hardcoded secret/credential' },
  { re: /(SELECT|INSERT|UPDATE|DELETE)\b[\s\S]{0,60}(\+|\$\{|%s|%d|f['"])/i, sev: 'high', msg: 'Possible SQL built via string interpolation (injection risk)' },
  { re: /\.innerHTML\s*=|document\.write\s*\(|dangerouslySetInnerHTML|insertAdjacentHTML/, sev: 'medium', msg: 'Direct DOM injection (XSS risk)' },
  { re: /\b(md5|sha1)\b/i, sev: 'medium', msg: 'Weak hash algorithm (MD5/SHA1)' },
  { re: /Math\.random\s*\(/, sev: 'low', msg: 'Math.random() is not cryptographically secure' },
  { re: /rejectUnauthorized\s*:\s*false|verify\s*=\s*False|CURLOPT_SSL_VERIFY(PEER|HOST)\s*,\s*(0|false)|NODE_TLS_REJECT_UNAUTHORIZED\s*=\s*['"]?0/i, sev: 'high', msg: 'Disabled/relaxed TLS certificate verification' }
];

lines.forEach((line, i) => {
  if (line.startsWith('+++') || line.startsWith('---') || line.startsWith('@@')) return;
  const isDiff = /^[+\- ]/.test(line);
  if (isDiff && !line.startsWith('+')) return;
  const addedCode = line.startsWith('+') ? line.slice(1) : line;
  checks.forEach(c => { if (c.re.test(addedCode)) add(i, c.sev, c.msg, line); });
});

return JSON.stringify({ tool: 'security_analysis', scope: 'added diff lines only', totalFindings: findings.length, findings }, null, 2);

const raw = ($('Parse Input').first().json.code || '');
const rawLines = raw.split('\n');
const added = rawLines
  .filter(l => l.startsWith('+') && !l.startsWith('+++'))
  .map(l => l.slice(1));
const code = added.join('\n');
const findings = [];
const add = (i, issue, snippet) =>
  findings.push({ line: i + 1, issue, snippet: (snippet || '').trim().slice(0, 160) });

rawLines.forEach((line, i) => {
  if (line.startsWith('+++') || line.startsWith('---') || line.startsWith('@@')) return;
  const isDiff = /^[+\- ]/.test(line);
  if (isDiff && !line.startsWith('+')) return;
  const addedCode = line.startsWith('+') ? line.slice(1) : line;

  if (/\bvar\s+[A-Za-z_$]/.test(addedCode)) add(i, 'Use of var (prefer let/const)', line);
  if (/console\.(log|debug|info|warn|error)\s*\(/.test(addedCode)) add(i, 'Leftover console logging', line);
  if (/(TODO|FIXME|HACK|XXX)\b/.test(addedCode)) add(i, 'TODO/FIXME marker', line);
  if (/[^=!<>]==[^=]/.test(addedCode) && !/===/.test(addedCode)) add(i, 'Loose equality (==)', line);
  if (/[^=!<>]!=[^=]/.test(addedCode) && !/!==/.test(addedCode)) add(i, 'Loose inequality (!=)', line);
});

const findAll = (re, label, snippetFn) => {
  let m;
  const r = new RegExp(re.source, re.flags.includes('g') ? re.flags : re.flags + 'g');
  while ((m = r.exec(code)) !== null) {
    const lineNo = code.slice(0, m.index).split('\n').length;
    add(lineNo - 1, label, snippetFn ? snippetFn(m) : m[0]);
  }
};
findAll(/catch\s*\([^)]*\)\s*\{\s*\}/, 'Swallowed error (empty catch block)');
findAll(/except[^\n:]*:\s*\n\s*pass/, 'Swallowed error (except: pass)', () => 'except ...: pass');

const commentLines = added.filter(l => /^\s*(\/\/|#|\*|\/\*)/.test(l)).length;
const ratio = added.length ? (commentLines / added.length) : 0;
const note = ratio < 0.03 && added.length > 40 ? 'Very few comments/docstrings relative to added code size' : null;

return JSON.stringify({
  tool: 'quality_regex_analysis',
  scope: 'added diff lines only',
  totalFindings: findings.length,
  commentRatio: Number(ratio.toFixed(3)),
  note,
  findings
}, null, 2);

// Format agent output and preserve tool metadata without exposing intermediate reasoning in GitHub.
const a = $input.first().json;
let report = a.output ?? a.text ?? '';
const steps = Array.isArray(a.intermediateSteps) ? a.intermediateSteps : [];

const reasoning = steps.map((s, idx) => {
  const action = s.action || {};
  return {
    step: idx + 1,
    thought: action.log ? String(action.log).trim() : '',
    tool: action.tool || '',
    toolInput: action.toolInput ?? '',
    observation: typeof s.observation === 'string' ? s.observation : JSON.stringify(s.observation)
  };
});
const toolsUsed = [...new Set(reasoning.map(r => r.tool).filter(Boolean))];

return [{ json: {
  success: true,
  report,
  reasoning,
  metadata: { stepsCount: reasoning.length, toolsUsed, skipped: false }
}}];

// Sanitize before posting to GitHub. Keep final report only; do not expose intermediate reasoning.
const item = $input.first().json;
let report = String(item.report || '').trim();

if (!report) {
  report = '# Code Review Report

## Overall Grade: N/A

## Executive Summary
The review agent returned an empty response. Manual review is required.

## Critical Issues (must fix)
- Review output was empty.

## Warnings (should fix)
- Automated review did not complete successfully.

## Suggestions (nice to have)
- Re-run the workflow after checking the n8n execution log.

## Strengths
- The workflow avoided posting unvalidated empty content.

## Dimension Scores
| Dimension | Score | One-line rationale |
| Quality | N/A | Review failed. |
| Security | N/A | Review failed. |
| Performance | N/A | Review failed. |
| Maintainability | N/A | Review failed. |

## Priority Action Items
1. [CRITICAL] Inspect the n8n execution log.
2. [HIGH] Re-run the review.
3. [MEDIUM] Review the PR manually.';
}

// Prevent accidental mass mentions and workflow noise.
report = report.replace(/@everyone/g, '@​everyone');
report = report.replace(/@here/g, '@​here');

// Remove accidental fenced hidden/internal scratchpad markers if the model emits them.
report = report.replace(/```(?:thought|reasoning|scratchpad)[\s\S]*?```/gi, '_Internal reasoning omitted._');

const requiredSections = [
  '# Code Review Report',
  '## Overall Grade:',
  '## Executive Summary',
  '## Critical Issues',
  '## Warnings',
  '## Suggestions',
  '## Strengths',
  '## Dimension Scores',
  '## Priority Action Items'
];
const missingSections = requiredSections.filter(s => !report.includes(s));

if (missingSections.length) {
  report = `# Code Review Report

## Overall Grade: N/A

## Executive Summary
The review output did not match the required report format. Manual review is required.

## Critical Issues (must fix)
- Invalid automated review format. Missing sections: ${missingSections.join(', ')}

## Warnings (should fix)
- The model output was rejected by the validation gate.

## Suggestions (nice to have)
- Re-run the workflow or adjust the prompt/output parser.

## Strengths
- The workflow avoided posting a malformed review as authoritative feedback.

## Dimension Scores
| Dimension | Score | One-line rationale |
| Quality | N/A | Review format invalid. |
| Security | N/A | Review format invalid. |
| Performance | N/A | Review format invalid. |
| Maintainability | N/A | Review format invalid. |

## Priority Action Items
1. [CRITICAL] Review this PR manually.
2. [HIGH] Inspect the failed agent output in n8n execution logs.
3. [MEDIUM] Re-run the workflow after fixing the format issue.

---

<details>
<summary>Rejected agent output</summary>

${report.slice(0, 8000)}

</details>`;
}

const MAX_REPORT_CHARS = 60000;
if (report.length > MAX_REPORT_CHARS) {
  report = report.slice(0, MAX_REPORT_CHARS) + '

_Report truncated by workflow before posting to GitHub._';
}

return [{ json: {
  ...item,
  report,
  metadata: { ...(item.metadata || {}), validation: { missingSections, reportChars: report.length } }
}}];
